mapper.select:
SELECT ROW_NUMBER() OVER (ORDER BY A1.ORDER_BY ASC) AS RNUM, A1.BANR_CD, A1.BANR_GB, COALESCE(A1.TITLE, '') AS TITLE, COALESCE(A1.LINK_GB, '') AS LINK_GB, COALESCE(A1.LINK_URL, '') AS LINK_URL, COALESCE((SELECT CONCAT(FILE_PATH, '/', SAVE_NM) FROM ARTFILE WHERE FILE_ID = CAST(A1.FILE_CD AS UNSIGNED) ORDER BY SEQ LIMIT 1), A1.IMG_URL, '') AS IMG_URL, COALESCE((SELECT CONCAT(FILE_PATH, '/thumb/', REPLACE(SAVE_NM, CONCAT('.', FILE_EXT), CONCAT('_128.', FILE_EXT))) FROM ARTFILE WHERE FILE_ID = CAST(A1.FILE_CD AS UNSIGNED) ORDER BY SEQ LIMIT 1), A1.IMG_URL, '') AS IMG_URL1, COALESCE(A1.FILE_CD, '') AS FILE_CD, COALESCE(A1.WIDTH_SIZE, 0) AS WIDTH_SIZE, COALESCE(A1.HEIGHT_SIZE, 0) AS HEIGHT_SIZE, COALESCE(A1.POSI_X, 0) AS POSI_X, COALESCE(A1.POSI_Y, 0) AS POSI_Y, DATE_FORMAT(A1.START_DTTM, '%Y-%m-%d %H:%i') AS START_DTTM, DATE_FORMAT(A1.END_DTTM, '%Y-%m-%d %H:%i') AS END_DTTM, COALESCE(A1.ORDER_BY, 0) AS ORDER_BY, A1.STAT_CODE FROM ARMBANR A1 WHERE A1.STAT_CODE = 'A'
AND DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i') >= DATE_FORMAT(A1.START_DTTM, '%Y-%m-%d %H:%i') AND DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i') <= DATE_FORMAT(A1.END_DTTM, '%Y-%m-%d %H:%i')
AND A1.BANR_GB = #{banrGb}
AND A1.TITLE LIKE CONCAT('%', #{searchKeyword}, '%')
AND A1.BODY LIKE CONCAT('%', #{searchKeyword}, '%')
ORDER BY A1.ORDER_BY ASC LIMIT #{lengthPage} OFFSET #{startIndex}
